import re


def normalize_title(value: str) -> str:
    return " ".join(value.strip().split()).title()


def slugify(value: str) -> str:
    value = normalize_title(value)
    value = re.sub(r"[^a-zA-Z0-9]+", "-", value)
    return value.strip("-")

